// TestExecuteBead_PostCommitReviewLandTimeoutReleasesLease verifies that a
// hanging review+land operation is bounded by the post-commit timeout, and
// releases the lease with an operator-attention event on expiry (AC1).
func TestExecuteBead_PostCommitReviewLandTimeoutReleasesLease(t *testing.T) {
	projectRoot := newDurableAuditProject(t)
	require.NoError(t, os.MkdirAll(filepath.Join(projectRoot, ddxroot.DirName), 0o755))
	store := bead.NewStore(ddxroot.JoinProject(projectRoot))
	require.NoError(t, store.Init())

	candidate := &bead.Bead{
		ID:       "ddx-post-commit-timeout",
		Title:    "Post-commit timeout test",
		Priority: 0,
	}
	require.NoError(t, store.Create(candidate))
	runGitInteg(t, projectRoot, "add", ".")
	runGitInteg(t, projectRoot, "commit", "-m", "chore: seed post-commit timeout test")
	head := runGitInteg(t, projectRoot, "rev-parse", "HEAD")

	// Mock executor that simulates a successful implementation.
	executor := ExecuteBeadExecutorFunc(func(ctx context.Context, id string) (ExecuteBeadReport, error) {
		return ExecuteBeadReport{
			BeadID:           id,
			AttemptID:        "attempt-post-commit-timeout",
			Status:           ExecuteBeadStatusSuccess,
			Detail:           "success",
			SessionID:        "sess-post-commit-timeout",
			BaseRev:          head,
			ResultRev:        head,
			ProjectRoot:      projectRoot,
			RequestedProfile: "standard",
			Harness:          "test-harness",
			Model:            "test-model",
		}, nil
	})

	// Mock reviewer that hangs indefinitely.
	reviewer := &stubBeadReviewer{
		reviewBead: func(ctx context.Context, beadID, resultRev string, impl ImplementerRouting) (*ReviewResult, error) {
			// Simulate a hanging reviewer by blocking on context cancellation.
			<-ctx.Done()
			return nil, ctx.Err()
		},
	}

	worker := &ExecuteBeadWorker{
		Store:    store,
		Executor: executor,
		Reviewer: reviewer,
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	// Run with a very short post-commit timeout to trigger the timeout quickly.
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:                 true,
		ProjectRoot:          projectRoot,
		PostMergeReview:      true,
		PostCommitTimeout:    100 * time.Millisecond,
		FinalizeDurableAudit: func(report ExecuteBeadReport) error { return nil },
	})

	require.NoError(t, err)
	require.NotNil(t, result)

	// Verify that the attempt was released (not closed).
	got, err := store.Get(context.Background(), candidate.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status, "bead should remain open after post-commit timeout")
	assert.Empty(t, got.Owner, "lease should be released on timeout")

	// Verify that an operator_attention event was emitted.
	events, err := store.Events(candidate.ID)
	require.NoError(t, err)
	found := false
	for _, ev := range events {
		if ev.Kind == "operator-attention" && ev.Summary == "wedged" {
			found = true
			assert.Contains(t, ev.Body, "post-commit", "operator-attention should reference post-commit phase")
			break
		}
	}
	assert.True(t, found, "should emit operator-attention event on post-commit timeout")
}

// TestExecuteBead_PostCommitReviewLandWithinBudgetCompletes verifies that a
// review+land that completes within the budget completes successfully without
// timing out (AC2).
func TestExecuteBead_PostCommitReviewLandWithinBudgetCompletes(t *testing.T) {
	projectRoot := newDurableAuditProject(t)
	require.NoError(t, os.MkdirAll(filepath.Join(projectRoot, ddxroot.DirName), 0o755))
	store := bead.NewStore(ddxroot.JoinProject(projectRoot))
	require.NoError(t, store.Init())

	candidate := &bead.Bead{
