		Title:    "Post-commit fast test",
		Priority: 0,
	}
	require.NoError(t, store.Create(candidate))
	runGitInteg(t, projectRoot, "add", ".")
	runGitInteg(t, projectRoot, "commit", "-m", "chore: seed post-commit fast test")
	head := runGitInteg(t, projectRoot, "rev-parse", "HEAD")

	// Mock executor that simulates a successful implementation.
	executor := ExecuteBeadExecutorFunc(func(ctx context.Context, id string) (ExecuteBeadReport, error) {
		return ExecuteBeadReport{
			BeadID:           id,
			AttemptID:        "attempt-post-commit-fast",
			Status:           ExecuteBeadStatusSuccess,
			Detail:           "success",
			SessionID:        "sess-post-commit-fast",
			BaseRev:          head,
			ResultRev:        head,
			ProjectRoot:      projectRoot,
			RequestedProfile: "standard",
			Harness:          "test-harness",
			Model:            "test-model",
		}, nil
	})

	// Mock reviewer that returns quickly.
	reviewer := &stubBeadReviewer{
		reviewBead: func(ctx context.Context, beadID, resultRev string, impl ImplementerRouting) (*ReviewResult, error) {
			// Return immediately with an APPROVE verdict.
			return &ReviewResult{
				Verdict:   VerdictApprove,
				Rationale: "looks good",
				PerAC:     []ExecutionReviewAC{{Number: 1, Grade: "PASS", Evidence: "verified"}},
			}, nil
		},
	}

	worker := &ExecuteBeadWorker{
		Store:    store,
		Executor: executor,
		Reviewer: reviewer,
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	// Run with a generous timeout since the reviewer returns quickly.
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:                 true,
		ProjectRoot:          projectRoot,
		PostMergeReview:      true,
		PostCommitTimeout:    5 * time.Second,
		FinalizeDurableAudit: func(report ExecuteBeadReport) error { return nil },
	})

	require.NoError(t, err)
	require.NotNil(t, result)
	require.Len(t, result.Results, 1)

	// Verify the attempt succeeded.
	report := result.Results[0]
