	assert.Equal(t, "APPROVE", report.ReviewVerdict)

	// Verify that the bead was closed.
	got, err := store.Get(context.Background(), candidate.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, got.Status, "bead should be closed on successful review")
	assert.Empty(t, got.Owner, "lease should be released after close")
}

