// is elapsed/progress-based, not field-emptiness-based. A running attempt
// with harness set and model/route empty that exceeds the timeout is released
// (AC3).
func TestExecuteBead_PostCommitTimeoutIsElapsedBased(t *testing.T) {
	projectRoot := newDurableAuditProject(t)
	require.NoError(t, os.MkdirAll(filepath.Join(projectRoot, ddxroot.DirName), 0o755))
