// flagPostCommitTimeoutForOperatorAttention flags a bead for operator attention
// after the post-commit review+land orchestration times out. The post-commit
// timeout is elapsed-based (not field-emptiness-based) so it fires when the
// review or land operation hangs indefinitely (ddx-b2846610).
func flagPostCommitTimeoutForOperatorAttention(store ExecuteBeadLoopStore, beadID, assignee, attemptID string, at time.Time, timeout time.Duration) {
	diagnosis := fmt.Sprintf(
		"post-commit timeout: review+land orchestration did not complete within %s; released lease and flagged for operator attention",
		timeout,
	)
	if releaser, ok := store.(leaseReleaser); ok && beadID != "" {
		_ = releaser.Release(beadID, assignee, "")
	}
	recordConsecutiveWedge(store, beadID, FailureModeProgressWatchdog, at)
	if store != nil && beadID != "" {
		body, _ := json.Marshal(map[string]any{
			"reason":     FailureModeProgressWatchdog,
			"bead_id":    beadID,
			"attempt_id": attemptID,
			"diagnosis":  diagnosis,
			"timeout":    timeout.String(),
		})
		_ = store.AppendEvent(beadID, bead.BeadEvent{
			Kind:      "operator_attention",
			Summary:   FailureModeProgressWatchdog,
			Body:      string(body),
			Actor:     assignee,
			Source:    "ddx work",
			CreatedAt: at,
		})
	}
}

